codeExamples.code:
/* Style invalid fields with a red border */
input:invalid,
textarea:invalid,
select:invalid {
  border-color: #ef4444;
}

/* Style valid fields with a green border */
input:valid,
textarea:valid,
select:valid {
  border-color: #22c55e;
}

/* Only show validation styles after user interaction */
input:user-invalid {
  border-color: #ef4444;
  background-color: #fef2f2;
}

input:user-valid {
  border-color: #22c55e;
  background-color: #f0fdf4;
}

/* Style the validation message */
input:invalid + .error-message {
  display: block;
  color: #ef4444;
  font-size: 0.875rem;
}
